const fs = require('fs');
const path = '/workspace/03_Editorial';
if (!fs.existsSync(path)) fs.mkdirSync(path, { recursive: true });

const body = $json.body || {};
if (!body.titulo || !body.pilar || !body.angulo || !body.formato) {
  return [{ json: { ok: false, error: 'Campos requeridos: titulo, pilar, angulo, formato' } }];
}

let maxNum = 0;
for (const file of fs.readdirSync(path)) {
  const m = file.match(/^P1_(\d{3})/);
  if (m) maxNum = Math.max(maxNum, parseInt(m[1], 10));
}
const next = String(maxNum + 1).padStart(3, '0');
const idPieza = `P1_${next}`;
const fecha = new Date().toISOString().split('T')[0];
const content = `# BRIEF DE CONTENIDO\n\n## METADATOS\n- **ID de pieza:** FG-${new Date().getFullYear()}-${idPieza}\n- **Fecha:** ${fecha}\n- **TÃ­tulo:** ${body.titulo}\n- **Pilar:** ${body.pilar}\n- **Ãngulo:** ${body.angulo}\n- **Formato:** ${body.formato}\n`;
const filePath = `${path}/${idPieza}_Brief.md`;
fs.writeFileSync(filePath, content, 'utf8');
return [{ json: { ok: true, pieza: idPieza, archivo: `03_Editorial/${idPieza}_Brief.md` } }];
